class ConditionalGenerator(nn.Module):
    """
    Conditions on a class label via embedding concatenated to the noise vector.
    num_classes: number of class labels (e.g. 10 for MNIST digits).
    """
    def __init__(self, latent_dim: int = 100, num_classes: int = 10, embed_dim: int = 50):
        super().__init__()
        self.embed = nn.Embedding(num_classes, embed_dim)
        self.net = nn.Sequential(
            nn.Linear(latent_dim + embed_dim, 256), nn.ReLU(),
            nn.Linear(256, 512), nn.ReLU(),
            nn.Linear(512, 784), nn.Tanh(),  # 28x28 flattened
        )

    def forward(self, z: Tensor, labels: Tensor) -> Tensor:
        cond = self.embed(labels)              # (B, embed_dim)
        return self.net(torch.cat([z, cond], dim=1))  # (B, 784)


class ConditionalDiscriminator(nn.Module):
    """Receives (x, label) pair; judges real vs fake conditioned on label."""
    def __init__(self, num_classes: int = 10, embed_dim: int = 50):
        super().__init__()
        self.embed = nn.Embedding(num_classes, embed_dim)
        self.net = nn.Sequential(
            nn.Linear(784 + embed_dim, 512), nn.LeakyReLU(0.2),
            nn.Linear(512, 256), nn.LeakyReLU(0.2),
            nn.Linear(256, 1),
        )

    def forward(self, x: Tensor, labels: Tensor) -> Tensor:
        cond = self.embed(labels)
        return self.net(torch.cat([x, cond], dim=1))
